class Solution {
    public String reverseOnlyLetters(String s) {
        StringBuilder result = new StringBuilder();
        boolean isLetter = false;
        for (char c : s.toCharArray()) {
            if (Character.isLetter(c)) {
                isLetter = !isLetter;
            }
            if (isLetter) {
                result.append(c);
            }
        }
        return result.reverse().toString();
    }
}
```

